const body = $input.first().json.body || $input.first().json;
const chatId = String(body.chatId || body.chat_id || '7713811206');
const mode = (body.mode || 'today').toLowerCase();

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

let fromDate, toDate, label;

if (mode === 'yesterday') {
  const yesterday = new Date(kstNow);
  yesterday.setDate(yesterday.getDate() - 1);
  fromDate = yesterday.toISOString().slice(0, 10) + ' 00:00:00';
  toDate = yesterday.toISOString().slice(0, 10) + ' 23:59:59';
  const m = yesterday.getMonth() + 1;
  const d = yesterday.getDate();
  label = `${m}/${d} (어제)`;
} else {
  fromDate = kstNow.toISOString().slice(0, 10) + ' 00:00:00';
  toDate = kstNow.toISOString().slice(0, 10) + ' 23:59:59';
  const m = kstNow.getMonth() + 1;
  const d = kstNow.getDate();
  const h = kstNow.getHours();
  const min = String(kstNow.getMinutes()).padStart(2, '0');
  label = `${m}/${d} ${h}:${min} 기준 (집계 중)`;
}

return [{ json: { chatId, mode, fromDate, toDate, label } }];

const dateInfo = $('날짜 계산').first().json;
let orderResp = $input.first().json;

if (typeof orderResp.data === 'string') {
  try { orderResp = JSON.parse(orderResp.data); } catch(e) {}
}
if (typeof orderResp === 'string') {
  try { orderResp = JSON.parse(orderResp); } catch(e) { orderResp = {}; }
}

function toArray(data) {
  if (Array.isArray(data)) return data;
  if (data && typeof data === 'object') return Object.values(data);
  return [];
}

const rawOrders = toArray(orderResp.list || []);
const orders = rawOrders.map(function(entry) {
  var o = entry.order || entry;
  o.basket = entry.basket || o.basket || [];
  if (!Array.isArray(o.basket)) o.basket = Object.values(o.basket);
  return o;
});

let totalRevenue = 0;
let cancelRevenue = 0;
let orderCount = 0;
let cancelCount = 0;
let pcCount = 0;
let mobileCount = 0;
const productSales = {};

const CANCEL_STATES = ['60', '70', '80'];

for (const order of orders) {
  const status = String(order.order_status || order.ord_state || '');
  const amount = parseInt(order.pay_price || order.total_product_price || order.start_price || 0);
  const payPath = String(order.pay_path || '').toLowerCase();

  if (CANCEL_STATES.includes(status)) {
    cancelCount++;
    cancelRevenue += amount;
    continue;
  }

  orderCount++;
  totalRevenue += amount;
  if (payPath.includes('mobile') || payPath.includes('m.')) mobileCount++;
  else pcCount++;

  for (const item of (order.basket || [])) {
    const name = (item.product_name || item.prd_name || '').slice(0, 25);
    const price = parseInt(item.sell_price || item.price || 0);
    const qty = parseInt(item.quantity || item.ea || 1);
    if (name) {
      if (!productSales[name]) productSales[name] = { revenue: 0, qty: 0 };
      productSales[name].revenue += price * qty;
      productSales[name].qty += qty;
    }
  }
}

const netRevenue = totalRevenue;
const avgOrder = orderCount > 0 ? Math.round(netRevenue / orderCount) : 0;

const topProducts = Object.entries(productSales)
  .sort((a, b) => b[1].revenue - a[1].revenue)
  .slice(0, 5);

const fmt = (n) => n.toLocaleString('ko-KR');

let msg = `<b>[\uB9E4\uCD9C] ${dateInfo.label}</b>\n`;
msg += `\uBA54\uC774\uD06C\uC0F5 \uC804\uC6A9\n`;
msg += `\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n`;
msg += `\u{1F4B0} \uC21C \uB9E4\uCD9C: <b>${fmt(netRevenue)}\uC6D0</b>\n`;
msg += `\u{1F4E6} \uC8FC\uBB38: ${orderCount}\uAC74`;
if (cancelCount > 0) msg += ` | \uCDE8\uC18C: ${cancelCount}\uAC74(-${fmt(cancelRevenue)}\uC6D0)`;
msg += `\n`;
msg += `\u{1F4B3} \uAC1D\uB2E8\uAC00: ${fmt(avgOrder)}\uC6D0\n`;
msg += `\u{1F4F1} PC ${pcCount}\uAC74 / \uBAA8\uBC14\uC77C ${mobileCount}\uAC74\n`;

if (topProducts.length > 0) {
  msg += `\n\u{1F3C6} TOP \uC0C1\uD488\n`;
  for (let i = 0; i < topProducts.length; i++) {
    const [name, data] = topProducts[i];
    msg += `  ${i + 1}. ${name} (${data.qty}\uAC1C, ${fmt(data.revenue)}\uC6D0)\n`;
  }
}

if (orderCount === 0 && cancelCount === 0) {
  msg = `<b>[\uB9E4\uCD9C] ${dateInfo.label}</b>\n\uBA54\uC774\uD06C\uC0F5 \uC804\uC6A9\n\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\uC8FC\uBB38\uC774 \uC544\uC9C1 \uC5C6\uC2B5\uB2C8\uB2E4.`;
}

return [{ json: { message: msg, chatId: dateInfo.chatId, revenue: netRevenue, orders: orderCount, cancels: cancelCount } }];
